from django import forms
from django.forms import inlineformset_factory
from PIL import Image

from .models import Product, Order, OrderItem


class ProductForm(forms.ModelForm):
    class Meta:
        model = Product
        fields = [
            'article', 'name', 'unit', 'price', 'discount',
            'quantity', 'description', 'photo',
            'category', 'manufacturer', 'supplier',
        ]

    def clean_price(self):
        price = self.cleaned_data.get('price')
        if price is not None and price < 0:
            raise forms.ValidationError('Цена не может быть отрицательной.')
        return price

    def clean_discount(self):
        discount = self.cleaned_data.get('discount')
        if discount is not None:
            if discount < 0 or discount > 100:
                raise forms.ValidationError('Скидка должна быть от 0 до 100%.')
        return discount

    def clean_photo(self):
        photo = self.cleaned_data.get('photo')
        if photo and hasattr(photo, 'image'):
            img = Image.open(photo)
            w, h = img.size
            if w > 300 or h > 200:
                raise forms.ValidationError(
                    f'Размер изображения {w}x{h} превышает допустимый 300x200.'
                )
        return photo


class OrderForm(forms.ModelForm):
    class Meta:
        model = Order
        fields = ['order_date', 'delivery_date', 'pickup_point', 'client', 'status']
        widgets = {
            'order_date': forms.DateInput(attrs={'type': 'date'}, format='%Y-%m-%d'),
            'delivery_date': forms.DateInput(attrs={'type': 'date'}, format='%Y-%m-%d'),
        }

    def clean(self):
        cleaned = super().clean()
        order_date = cleaned.get('order_date')
        delivery_date = cleaned.get('delivery_date')
        if order_date and delivery_date and delivery_date <= order_date:
            raise forms.ValidationError(
                'Дата доставки должна быть позже даты заказа.'
            )
        return cleaned


OrderItemFormSet = inlineformset_factory(
    Order,
    OrderItem,
    fields=['product', 'quantity'],
    extra=1,
    min_num=1,
    validate_min=True,
    max_num=100,
    can_delete=True,
)
